1	import { useState, useEffect } from 'react'
2	
3	interface SourceData {
4	  content: string | null
5	  found: boolean
6	}
7	
8	interface ParsedSource {
9	  id: string
10	  name: string
11	  query: string
12	  purpose: string
13	}
14	
15	interface SourceSection {
16	  title: string
17	  sources: ParsedSource[]
18	}
19	
20	function parseSources(md: string): SourceSection[] {
21	  const sections: SourceSection[] = []
22	  let currentTitle = ''
23	  let currentSources: ParsedSource[] = []
24	
25	  for (const line of md.split('\n')) {
26	    const headerMatch = line.match(/^### (.+)/)
27	    if (headerMatch) {
28	      if (currentTitle && currentSources.length > 0) {
29	        sections.push({ title: currentTitle, sources: currentSources })
30	      }
31	      currentTitle = headerMatch[1]
32	      currentSources = []
33	      continue
34	    }
35	    const rowMatch = line.match(/^\|\s*(\d+)\s*\|\s*(.+?)\s*\|\s*(.+?)\s*\|\s*(.+?)\s*\|$/)
36	    if (rowMatch) {
37	      currentSources.push({
38	        id: rowMatch[1],
39	        name: rowMatch[2].trim(),
40	        query: rowMatch[3].trim(),
41	        purpose: rowMatch[4].trim(),
42	      })
43	    }
44	  }
45	  if (currentTitle && currentSources.length > 0) {
46	    sections.push({ title: currentTitle, sources: currentSources })
47	  }
48	  return sections
49	}
